<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#121212;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin-top:10px;}
  button{background:#1e88e5;border:none;padding:8px 12px;margin:2px;color:white;border-radius:4px;cursor:pointer;}
  button:hover{background:#1565c0;}
  canvas{border:1px solid #444;background:#000;}
</style>
</head>
<body>
<canvas id="sand" width="400" height="400"></canvas>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const w = 80, h = 80; // grid size
  const cellSize = canvas.width / w;
  const materials = { empty:0, sand:1, water:2, wall:3, acid:4 };
  const materialNames = ['empty','sand','water','wall','acid'];
  let grid = new Uint8Array(w*h);
  let nextGrid = new Uint8Array(w*h);

  // API
  window.sim = {
    w, h,
    tick(n){ for(let i=0;i<n;i++) step(); },
    get(x,y){ return materialNames[grid[y*w+x]]; },
    set(x,y,m){ if(m in materials) grid[y*w+x]=materials[m]; },
    clear(){ grid.fill(0); }
  };

  function idx(x,y){ return y*w + x; }

  // Simulation step
  function step(){
    nextGrid.set(grid);
    for(let y=h-1;y>=0;y--){
      for(let x=0;x<w;x++){
        const i = idx(x,y);
        const mat = grid[i];
        if(mat===materials.sand) moveSand(x,y,i);
        else if(mat===materials.water) moveWater(x,y,i);
        else if(mat===materials.acid) moveAcid(x,y,i);
      }
    }
    // swap grids
    [grid,nextGrid] = [nextGrid,grid];
  }

  function moveSand(x,y,i){
    const below = idx(x,y+1);
    if(y+1<h && grid[below]===materials.empty){ nextGrid[i]=0; nextGrid[below]=materials.sand; }
    else if(y+1<h && (grid[below]===materials.water||grid[below]===materials.acid)){
      // swap
      nextGrid[i]=0; nextGrid[below]=materials.sand;
    }else{
      const dirs = [ -1, 1 ];
      shuffle(dirs);
      for(const d of dirs){
        const nx=x+d, ny=y+1;
        if(nx>=0&&nx<w&&ny<h && grid[idx(nx,ny)]===materials.empty){
          nextGrid[i]=0; nextGrid[idx(nx,ny)]=materials.sand; return;
        }
      }
    }
  }

  function moveWater(x,y,i){
    const below = idx(x,y+1);
    if(y+1<h && grid[below]===materials.empty){ nextGrid[i]=0; nextGrid[below]=materials.water; }
    else{
      const dirs=[-1,1];
      shuffle(dirs);
      for(const d of dirs){
        const nx=x+d, ny=y;
        if(nx>=0&&nx<w && grid[idx(nx,ny)]===materials.empty){
          nextGrid[i]=0; nextGrid[idx(nx,ny)]=materials.water; return;
        }
      }
    }
  }

  function moveAcid(x,y,i){
    const below = idx(x,y+1);
    if(y+1<h && grid[below]===materials.empty){ nextGrid[i]=0; nextGrid[below]=materials.acid; }
    else{
      // dissolve
      const dirs=[-1,1];
      shuffle(dirs);
      for(const d of dirs){
        const nx=x+d, ny=y;
        if(nx>=0&&nx<w && grid[idx(nx,ny)]===materials.sand){ nextGrid[i]=0; nextGrid[idx(nx,ny)]=materials.empty; return;}
      }
      // try below
      if(y+1<h && (grid[below]===materials.sand||grid[below]===materials.wall)){
        nextGrid[i]=0; nextGrid[below]=materials.acid;
        if(grid[below]!==materials.wall){ nextGrid[idx(x,y+1)]=materials.empty;}
        else{ // wall erodes
          nextGrid[idx(x,y+1)]=materials.empty;
        }
      }else{
        for(const d of dirs){
          const nx=x+d, ny=y;
          if(nx>=0&&nx<w && grid[idx(nx,ny)]===materials.sand){ nextGrid[i]=0; nextGrid[idx(nx,ny)]=materials.empty; return;}
        }
      }
    }
  }

  function shuffle(a){ for(let i=a.length-1;i>0;i--){ const j=Math.floor(Math.random()*(i+1)); [a[i],a[j]]=[a[j],a[i]];}}

  // Rendering
  function render(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        const mat = grid[idx(x,y)];
        if(mat===materials.empty) continue;
        switch(mat){
          case materials.sand: ctx.fillStyle='#d4af37'; break;
          case materials.water: ctx.fillStyle='#2196f3'; break;
          case materials.wall: ctx.fillStyle='#757575'; break;
          case materials.acid: ctx.fillStyle='#00e676'; break;
        }
        ctx.fillRect(x*cellSize, y*cellSize, cellSize, cellSize);
      }
    }
  }

  // Animation loop
  function animate(){ step(); render(); requestAnimationFrame(animate); }
  requestAnimationFrame(animate);

  // UI
  let currentMat = materials.sand;
  document.getElementById('mat-sand').onclick=()=>currentMat=materials.sand;
  document.getElementById('mat-water').onclick=()=>currentMat=materials.water;
  document.getElementById('mat-wall').onclick=()=>currentMat=materials.wall;
  document.getElementById('mat-acid').onclick=()=>currentMat=materials.acid;
  document.getElementById('mat-empty').onclick=()=>currentMat=materials.empty;
  document.getElementById('clear').onclick=()=>grid.fill(0);

  let drawing=false;
  canvas.addEventListener('mousedown',e=>{drawing=true; paint(e);});
  canvas.addEventListener('mouseup',()=>drawing=false);
  canvas.addEventListener('mouseleave',()=>drawing=false);
  canvas.addEventListener('mousemove',e=>{ if(drawing) paint(e); });

  function paint(e){
    const rect=canvas.getBoundingClientRect();
    const x=Math.floor((e.clientX-rect.left)/cellSize);
    const y=Math.floor((e.clientY-rect.top)/cellSize);
    if(x>=0&&x<w&&y>=0&&y<h) grid[idx(x,y)]=currentMat;
  }
})();
</script>
</body>
</html>
